189	\subsection{The Albanese witness bundle}
190	
191	Before stating the existence theorem, we package its conclusion into a single structure --- the \emph{Albanese witness} of $C$. This bundling reverses the quantifier order of the classical statement (see Remark~\ref{rem:JacobianWitness_quantifier_order}) and is the data structure consumed by the \texttt{Jacobian} family of declarations in this file and by the \texttt{AbelJacobi} interface of Chapter~\ref{chap:AbelJacobi}.
192	
193	\begin{definition}
194	[Albanese witness for a curve]
195	  \label{def:JacobianWitness}
196	  \lean{AlgebraicGeometry.JacobianWitness}
197	  \uses{def:IsAlbanese, def:genus}
198	  An \emph{Albanese witness} for the smooth proper geometrically irreducible curve $C$ over $k$ is a bundle of the following seven fields:
199	  \begin{itemize}
200	    \item $J$: an object of the category of $k$-schemes over $\Spec k$ --- the candidate Albanese object.
201	    \item $\mathtt{grpObj}$: a group-object structure on $J$ in the category of $k$-schemes over $\Spec k$.
202	    \item $\mathtt{proper}$: a proof that the structure morphism $J \to \Spec k$ is proper.
203	    \item $\mathtt{smooth}$: a proof that the structure morphism $J \to \Spec k$ is smooth.
204	    \item $\mathtt{geomIrred}$: a proof that the structure morphism $J \to \Spec k$ is geometrically irreducible.
205	    \item $\mathtt{smoothGenus}$: a proof that the structure morphism $J \to \Spec k$ is smooth of relative dimension $g(C)$. This refines $\mathtt{smooth}$ at the specific relative dimension $\genus\, C$ (see Remark~\ref{rem:JacobianWitness_smooth_redundancy}).
206	    \item $\mathtt{isAlbaneseFor}$: a proof that, for every $k$-rational marked point $P \in C(k)$, the scheme $J$ together with its group-object, proper, smooth, and geometrically-irreducible structures satisfies the Albanese universal property for the pointed curve $(C, P)$ in the sense of Definition~\ref{def:IsAlbanese}.
207	  \end{itemize}
208	  Formally, an Albanese witness is a Lean-level record (a structure) whose name is \texttt{JacobianWitness}.
209	\end{definition}
210	
211	\begin{remark}
212	  \label{rem:JacobianWitness_quantifier_order}
213	  \uses{def:JacobianWitness}
214	  The classical phrasing of the existence statement of an Albanese variety is
215	  \[
216	    \forall\, P \in C(k),\ \exists\, J,\ J \text{ is an Albanese object for } (C, P).
217	  \]
218	  The witness bundle reverses these quantifiers: a single $J$ is chosen once (intrinsic to $C$), and the marked-point-dependent data is recorded as the family-valued field
219	  \[
220	    \mathtt{isAlbaneseFor} \colon \forall\, P \in C(k),\ \mathrm{IsAlbanese}\,C\,P\,J.
221	  \]
222	  Mathematically this reversal is justified because the underlying scheme of any Albanese object is intrinsic to $C$: a different choice of $P \in C(k)$ alters the universal morphism $\iota_P \colon C \to J$ by a translation of $J$, which is an automorphism of $J$, and so leaves $J$ unchanged as a scheme. The reversed bundling is what makes the per-$P$ projection in Chapter~\ref{chap:AbelJacobi} clean: $\mathtt{Jacobian.ofCurve}$, $\mathtt{Jacobian.comp\_ofCurve}$, and $\mathtt{Jacobian.exists\_unique\_ofCurve\_comp}$ each take a marked point $P$ as input and project the corresponding component of $\mathtt{isAlbaneseFor}\,P$ via the extraction trio (Definition~\ref{def:IsAlbanese_ofCurve}, Lemmas~\ref{lem:IsAlbanese_comp_ofCurve}, \ref{lem:IsAlbanese_exists_unique_ofCurve_comp}).
223	\end{remark}
224	
225	\begin{remark}
226	  \label{rem:JacobianWitness_smooth_redundancy}
227	  \uses{def:JacobianWitness}
228	  The fields $\mathtt{smooth}$ and $\mathtt{smoothGenus}$ of an Albanese witness are mathematically redundant: the relative-dimension version implies the unqualified version via Mathlib's \texttt{AlgebraicGeometry.SmoothOfRelativeDimension.smooth}. Keeping both fields is a Lean-level convenience: $\mathtt{smooth}$ is the form required by the typeclass binder of \texttt{IsAlbanese} (and by the protected $\mathtt{Jacobian.instGrpObj}$ projection), whereas $\mathtt{smoothGenus}$ is the form required by the protected $\mathtt{Jacobian.smoothOfRelativeDimension\_genus}$ projection. The redundancy carries no mathematical cost (the two fields agree) and no soundness cost (deriving one from the other would only re-run the same Mathlib instance synthesis at the projection sites).
229	\end{remark}
230	
231	\begin{theorem}\leanok
232	[Existence of an Albanese variety uniformly over the marked point]
233	  \label{thm:nonempty_jacobianWitness}
234	  \lean{AlgebraicGeometry.nonempty_jacobianWitness}
235	  \uses{def:IsAlbanese, def:Jacobian, def:genus, def:JacobianWitness}
236	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. There exists a smooth proper geometrically irreducible group scheme $J$ over $k$ of relative dimension $g(C)$ such that, for every $k$-rational point $P \in C(k)$, the scheme $J$ is an Albanese object for the pointed curve $(C, P)$ in the sense of Definition~\ref{def:IsAlbanese}. Equivalently, the type of Albanese witnesses for $C$ (Definition~\ref{def:JacobianWitness}) is non-empty.
237	\end{theorem}
238	
239	\begin{proof}
240	  \uses{def:IsAlbanese, def:genus}
241	  \leanok
242	  The proof is split into three classical constructions plus the genus-$0$ sub-case absorbed into the same witness. Each route produces the same intrinsic scheme $J$; only the universal morphism $\iota_P \colon C \to J$ varies with the marked point $P$. We outline each route and name the Mathlib infrastructure each one requires.
243	
244	  \paragraph{(0) Reduction to a $P$-independent witness.}
